const topic = $.input.contentTopic || '';
const query = 'trending Instagram Reels TikTok ' + topic + ' viral content ideas';
return { query };

const topic = $.input.contentTopic;
const count = $.input.numberOfPosts || 5;
const results = $.steps.researchTrends.response.results || [];
let trends = '';
results.forEach((r, i) => { trends += (i + 1) + '. ' + (r.title || r.url) + ': ' + (r.text || '').slice(0, 150) + '
'; });

const prompt = 'You are a social media content strategist specializing in short-form video. Generate a content plan for ' + count + ' social media video posts.

TOPIC/NICHE: ' + topic + '

TRENDING INSIGHTS:
' + trends + '

Return ONLY valid JSON:
{
  "posts": [
    {
      "postNumber": 1,
      "concept": "video concept in one line",
      "hook": "first 3-second hook text",
      "script": "full narration script (15-30 seconds)",
      "caption": "Instagram/TikTok caption with emoji",
      "hashtags": ["hashtag1", "hashtag2"],
      "musicStyle": "background music suggestion",
      "visualStyle": "description of visual treatment",
      "bestPostingTime": "recommended day and time",
      "platform": "IG Reels/TikTok/YT Shorts/All"
    }
  ],
  "weeklyTheme": "overarching content theme",
  "contentStrategy": "brief strategy notes"
}';

return { prompt };

let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { posts: [], weeklyTheme: raw.slice(0, 200) }; }

const ai = $.steps.parseAI.output;
const posts = ai.posts || [];
const date = new Date().toISOString().split('T')[0];
const rows = posts.map(p => [
  date,
  p.postNumber || '',
  p.concept || '',
  p.hook || '',
  p.script || '',
  p.caption || '',
  (p.hashtags || []).join(' '),
  p.platform || 'All',
  p.bestPostingTime || '',
  'Draft'
]);
const slackText = 'Content plan generated: ' + posts.length + ' posts for "' + $.input.contentTopic + '" | Theme: ' + (ai.weeklyTheme || 'N/A');
return { rows, slackText };
